var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"3개월 뒤\\n<color=#ffd34c>CSE Lv.2</color> 오염 지대","JPN":"3か月後\\n<color=#ffd34c>CSE Lv.2</color>汚染地帯","ENG":"3 months later\\n<color=#ffd34c>CSE Level 2</color> Corrupted Area","TWN":"3個月後\\n<color=#ffd34c>CSE Lv.2</color>污染區"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"젠장! 2단계 현장이라고 너무 얕봤어!","JPN":"くそ！　第2段階だからと舐めすぎた！","ENG":"Dammit! We underestimated the Level 2 situation!","TWN":"該死！太小看2級現場了！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_02"},{"id":"L10_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"인지 왜곡 필터 밖으로 침식체가 빠져나갈지도 몰라!","JPN":"認知歪曲フィルターの外に侵食体が抜け出すかもしれない！","ENG":"C.O.s might escape and get past the awareness distortion filter!","TWN":"侵蝕體或許會透過認知失真濾波器逃走！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"침식체의 개체수가 너무 많다! 흩어져서 각개격파 한다!","JPN":"侵食体の個体数が多すぎる！　手分けしてそれぞれ撃破するぞ！","ENG":"There are too many of them! Spread out and kill them all!","TWN":"侵蝕體數量太多了！將它們分散開來，單獨擊破！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SWORD_ADMIN_NULL_NULL","text":{"KOREA":"대장님, 이쪽 구역의 침식체들이 필터 밖으로 이탈했습니다!","JPN":"隊長、こちらの区域の侵食体がフィルターの外に離脱しました！","ENG":"Captain, the C.O.s in this area have escaped the filter!","TWN":"隊長，這片區域的侵蝕體開始向濾波器外逃跑了！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L14_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"어서 추적해! 작전 구역 밖은 민간 거주구역이다!","JPN":"直ちに追跡しろ！　作戦区域の外は民間区域だ！","ENG":"Track them down! Outside of the operation area is a civilian residential area!","TWN":"追上去！作戰區域外是平民住宅區！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L15_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"민간 피해는 최소화해야 한다!","JPN":"民間人の被害は最小限に抑えるんだ！","ENG":"Minimize civilian casualties!","TWN":"必須將平民傷害降到最低！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"작전 지휘를 맡은 야크샤 전대의 앨리스다.","JPN":"作戦の指揮を執る、ヤクシャー戦隊のアリスだ。","ENG":"This is Alice of the Yaksha Division, the one in charge of this operation.","TWN":"這裡是是負責指揮作戰的夜叉戰隊員，艾莉絲。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L18_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 제4 수색전대 <color=#ffd34c>야크샤</color>\\n견습 대원 앨리스","JPN":"管理局第4捜索戦隊<color=#ffd34c>ヤクシャー</color>\\n見習い隊員アリス","ENG":"Administration 4th Recon Division <color=#ffd34c>Yaksha</color>\\nTrainee Alice","TWN":"管理局第4偵察戰隊<color=#ffd34c>夜叉</color>\\n實習戰隊員艾莉絲"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"전대원, 현위치에서 대열을 사수할 것. 작전 구역에서 이탈한 녀석들은 내가 맡겠다.","JPN":"全隊員、現在位置で隊列を守れ。作戦区域から離脱した個体はアタシに任せろ。","ENG":"All units, maintain formation in your current location. I'll take care of the C.O.s that have escaped.","TWN":"全體隊員，請保持隊形死守你們現在的位置。我來處理那些逃離作戰區域的傢伙。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"전대원님?","JPN":"アリスさん？","ENG":"Ms. Braidwood?","TWN":"艾莉絲戰隊員？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"그렇지만 이탈한 침식체들이 어디로 향할지 모르지 않습니까?","JPN":"ですが、離脱した侵食体がどこに向かうかわかりません！","ENG":"But you don't know where they're headed.","TWN":"但是，你知道逃跑的侵蝕體去了哪裡嗎？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"괜찮아. 녀석들은 외곽 지역에 있는 폐공장으로 모일 거야.","JPN":"大丈夫だ。奴らは外郭の廃工場に集まるはず。","ENG":"It's all right. The C.O.s are going to gather at the abandoned factory in the outskirts.","TWN":"別擔心。我會把那些傢伙聚集在郊區的一個廢棄工廠。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"몇 년 전에 철거 허가가 떨어진 곳이야. 여기라면 마음껏 싸워도 괜찮겠지.","JPN":"あそこは数年前に撤去の許可が下りている。そこなら派手に戦っても構わないだろう。","ENG":"A demolition permit was issued here a few years ago. I should be able to fight without worrying here.","TWN":"那裡幾年前就下達了拆除許可。在這裡想怎麼戰鬥都可以。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"네? 하지만 어떻게……!?","JPN":"はい？　ですが、どうやって……！？","ENG":"Huh? But how...?!","TWN":"嗯？但是要怎麼樣……？！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"현장에선 이가 없으면, 잇몸으로라도 해결하라고 배웠어.","JPN":"現場では手段を選ぶなと教えられた。","ENG":"I was taught to work with what I have.","TWN":"有人教過我，山不轉自轉。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"내가 가진 보급용 이터니움을 뿌려두었다. 냄새를 맡은 녀석들이 곧 여기로 몰려들겠지.","JPN":"アタシが持っている普及用のエタニウムを撒いておいた。奴らが匂いを嗅ぎつけてここへ集まるだろう。","ENG":"I scattered the Eternium supply I had, so they'll smell that and gather here.","TWN":"我用補給永恆之金作餌。它們聞到味道很快就會蜂擁前往這裡的。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"좋아. 때마침 도착했네.","JPN":"あ、ちょうど着いたようだな。","ENG":"All right, Looks like they're here.","TWN":"好。看來來得正是時候。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L33_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"다들 각자 작전 구역을 정리한 뒤에, 여유가 되면 이쪽도 좀 도와줘.","JPN":"皆、それぞれ作戦区域が片付いた後、手が空いてたら手伝ってくれ。","ENG":"Once everyone's done taking care of each area, come help me over here if you got time.","TWN":"大家清理好各自的戰區後，有時間的話請來這裡幫忙。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"자, 어디 실력 발휘 좀 해볼까?","JPN":"さて、腕の見せ所だな！","ENG":"Now, let's do this.","TWN":"現在，讓我來看看能發揮多少實力吧？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 현실 전초기지, <color=#ffd34c>쉘터 No.72</color>\\n관리국 제4 수색전대 <color=#ffd34c>야크샤</color> 임시 본부","JPN":"管理局現実前哨基地、<color=#ffd34c>シェルターNo.72</color>\\n管理局第4捜索戦隊<color=#ffd34c>ヤクシャー</color>臨時本部","ENG":"Administration's Normalside Frontier Base, <color=#ffd34c>Shelter No. 72</color>\\nAdministration 4th Recon Division <color=#ffd34c>Yaksha</color>'s temporary HQ","TWN":"管理局現世前哨站，<color=#ffd34c>72號庇護所</color>\\n管理局第4偵察戰隊<color=#ffd34c>夜叉</color>臨時總部"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"축하해. CSE 레벨 2단계 현장을 혼자 잘 마무리했다면서?","JPN":"おめでとう。CSEレベル2段階の現場を一人で片付けたらしいじゃない。","ENG":"Congrats. I heard you managed to neutralize a CSE Level 2 situation all on your own.","TWN":"恭喜。我聽說你獨自完成了CSE等級2的現場任務？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"이렇게 빨리 전대원으로서 성장하게 되다니, 기특한걸?","JPN":"こんなに早く戦隊員として成長を遂げるとは……大したものね。","ENG":"Seeing how you're quickly becoming a member of our division makes me proud.","TWN":"難得你能成長的這麼快。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"이젠 길고양이라고 부르지도 못하겠네. 그럼 어떤 애칭이 좋으려나?","JPN":"もう野良猫とは呼べないかな。どんなあだ名がいいかしら～？","ENG":"Guess I can't call you stray cat from now on. Now then, what other nicknames will suit you?","TWN":"看來不能再叫你流浪貓了，換個什麼外號比較好呢……？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"}}}},{"id":"L47_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"애칭은 뭔 놈에 애칭이야! 그냥 이름으로 부르라고!","JPN":"あだ名ってなんだよ！　名前で呼べよ！","ENG":"Quit it with the nicknames! Just call me by my name!","TWN":"要什麼外號！叫我的名字就可以了！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"}}}},{"id":"L48_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그보다 다음 임무는…… ","JPN":"それより、次の任務は…… ","ENG":"Other than that, the next mission is...","TWN":"比起這個，下一個任務是……"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"으음?","JPN":"うん？","ENG":"Mm?","TWN":"唔？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"}}}},{"id":"L1_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"간다!","JPN":"行くぞ！","ENG":"Here it goes!","TWN":"我上了！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L2_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"필──! 살──!","JPN":"必、殺─！","ENG":"Speciallll! Skilllll!","TWN":"必……！殺……！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"앨리스 익스플로저어어어어어어언──!","JPN":"アリスエクスプロージョン──！","ENG":"Alice EXPLOOOOOSION!!!","TWN":"艾莉絲爆裂……！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"너, 너……! 내가 그거 지우라고 했지……!?","JPN":"お、おまえ……！　それ消せって言っただろう！","ENG":"H-hey...! I told you to delete that...!!","TWN":"你、你……！你怎麼還沒把那個刪掉……？！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"키히히, 그래서 이번에는 어떤 필살기로 해치워버린 겁니까요?","JPN":"キヒヒ！　で、今回はどの必殺技でやっつけたんでやんすか？","ENG":"Kekeke. Did you use your special skill to defeat them all this time too?","TWN":"呵呵呵，來呀，用你的必殺技把這個也刪掉呀？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"이 완두콩 같은 게! 그거 이리 안 내놔!","JPN":"このちんちくりんめ！　それをよこせ！","ENG":"Green pea! Gimme that!","TWN":"你這個臭豌豆！還不給我放開！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"헹! 싫습니다요!","JPN":"へへん、嫌でやんす！","ENG":"Hmph! Not a chance!","TWN":"哼！才不要咧！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L12_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"저장했습니다요! 백업 완료입니다요! 영구박제인 것입니다요!","JPN":"保存したでやんす！　バックアップ完了でやんす！　永久保存でやんす！","ENG":"It's saved! I made copies! It's not going anywhere forever!","TWN":"保存！然後備份！現在你再也刪不掉了！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"이게……!!","JPN":"こんの……！！","ENG":"Why you...!!","TWN":"你……！！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L14_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"우갸아아악……!!","JPN":"うぎゃああああ……！！","ENG":"Uwaaagh...!!","TWN":"嗚哇啊啊啊……！！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_CARTOON_04"},{"id":"L18_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"뿌에에에에엥……!! 부전대장님……!!","JPN":"ふええええん……！！　副戦隊長……！！","ENG":"WAAAAAH...!! Deputy Commander...!","TWN":"嗚啊啊……！！副戰隊長……！！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"흐윽, 신참 녀석이 또 때렸습니다요…….","JPN":"うぐっ、新入りにまた殴られたでやんす……","ENG":"Hngh, the rookie hit me again...","TWN":"嗚嗚，新人又打我……"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"혹이 났습니다요. 뇌세포가 죽었습니다요. 관리국의 손실입니다요…….","JPN":"頭にこぶができたでやんす。脳細胞やられたでやんす。管理局の大損失でやんす……","ENG":"I have another bump. My brain cells are dead. This is a loss for the Administration...","TWN":"我的頭又冒了一個大包。腦細胞都死光光了。這是管理局的損失……"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"괜찮아, 금방 나을 거야.","JPN":"大丈夫、すぐ治るから。","ENG":"It's all right. You'll be better in no time.","TWN":"沒關係，你很快就會好起來的。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L22_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"자, 뚝!","JPN":"はい、泣き止んで！","ENG":"Now, no more crying!","TWN":"好了，不哭！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"……뚝.","JPN":"……うっ。","ENG":"...Okay.","TWN":"……嗯。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"너무 오냐오냐 해주는 거 아니야? 그러니까 꼬맹이 버릇이 나빠지지.","JPN":"甘やかしすぎじゃねえか？　だから悪い癖がつくんだよ。","ENG":"Don't you think you're coddling her too much? That's why her manners are terrible.","TWN":"你是不是太寵她了？所以，小鬼才越來越不像樣。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"왜? 너도 오냐오냐 받고 싶어?","JPN":"あら、どうして？　あなたも甘やかされたいの？","ENG":"Hmm? Do you want me to coddle you too?","TWN":"怎麼？你也想被寵嗎？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L29_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"크윽! 그딴 거 필요 없거든!?","JPN":"うっ……！　そんなわけあるか！","ENG":"Kgh! I don't need that!","TWN":"咳！沒那個必要？！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L30_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"후후, 다들 사이가 돈독해진 것 같아서 기분이 좋네.","JPN":"ふふ、皆仲良くなったみたいで嬉しいね。","ENG":"Fu fuu, I'm glad that everyone's getting along with each other.","TWN":"呵呵，看來大家的關係變得更加親密了。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"}}}},{"id":"L31_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"꼭 가족이라도 된 것 같은 느낌이야.","JPN":"まるで家族にでもなったような気分。","ENG":"It really feels like we're a family.","TWN":"感覺我們已經是一家人了。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"}}}},{"id":"L33_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그럼, 이제 슬슬 수색 작전을 재개해도 괜찮으려나?","JPN":"さて、そろそろ捜索作戦を再開してもいいかな？","ENG":"I think it's time we can restart our search operation.","TWN":"我覺得是時候展開偵察作戰了。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L34_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"수색 작전이라고?","JPN":"捜索作戦って？","ENG":"Search operation?","TWN":"偵察作戰？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"우리가 현실에서 이렇게 오래 주둔할 수 있었던 건, 관리국이 편의를 봐준 것뿐이거든.","JPN":"私たちが現実世界でこんなに長い間駐屯できたのは、管理局が便宜を図ってくれたからよ。","ENG":"The only reason we could stay in the Normalside for this long is because the Administration was lenient with us.","TWN":"我們能夠在現世中駐紮這麼久，是因為管理局給了我們方便。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"원래 우리 야크샤는 이면세계 최전선에서 활동하는 전대니까.","JPN":"もともと私たちヤクシャーは、裏世界の最前線で活動する戦隊だからね。","ENG":"Yaksha is a division that normally works on the forefront of the Counterside.","TWN":"我們夜叉原本是在異界前線工作的戰隊。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"이면세계라고 하면…….","JPN":"裏世界というと……","ENG":"Counterside...?","TWN":"說到異界……"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그 침식체가 원래 살고 있는 곳이라고 했지?","JPN":"侵食体が本来住んでいる場所だろ。","ENG":"Isn't that where those C.O.s come from?","TWN":"你說那是侵蝕體原本居住的地方吧？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"우리 야크샤의 임무는 다른 전대보다 한 발 앞서, 이면세계를 수색하는 것.","JPN":"私たちヤクシャーの任務は、他の戦隊より一足先に裏世界を捜索すること。","ENG":"Yaksha's mission is to search the Counterside one step ahead of the other divisions.","TWN":"我們夜叉的任務是比其他戰隊先行一步偵察異界。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"관리국은 우리가 수색한 정보를 바탕으로 이면세계의 위험도를 결정하고, 작전을 구상하지.","JPN":"私たちの捜索による情報を元に、管理局は裏世界の危険度を測り、作戦を練る。","ENG":"The Administration uses the intel we gather from our searches to determine the level of danger and devise an operation.","TWN":"管理局會根據我們偵察到的資訊，來確定異界的危險程度，制定作戰計畫。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"꽤 중요한 임무잖아?","JPN":"けっこう重要な任務じゃないか。","ENG":"That sounds pretty important.","TWN":"這不是個很重要的任務嗎？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"야크샤 전대가 환상종 카운터만으로 구성된 것도 이유가 있는 거야?","JPN":"ヤクシャー戦隊が幻想種のカウンターのみで構成されてるのも、何か関係があるのか？","ENG":"Is that also why the Yaksha Division is composed only of Bygone Counters?","TWN":"難道夜叉戰隊只有夢幻品種制裁者，是因為這個原因嗎？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"맞아. 역시 눈치가 빠르네.","JPN":"さすが、察しがいいね。","ENG":"Correct. I knew you caught on fast.","TWN":"沒錯。你果然很聰明。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"환상종 카운터는 대부분 침식내성이 뛰어나서 장기간 다이브가 가능하거든.","JPN":"幻想種のカウンターのほとんどは侵食耐性が高いから、長時間のダイブができるの。","ENG":"Most Bygone Counters are more resilient to Corruption, so they can dive longer.","TWN":"大多數夢幻品種制裁者都具有出色的抗侵蝕性，可以進行長時間躍入。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"또 구성원 모두가 동물적인 초감각을 가지고 있어서 위험에 빠르게 대처할 수 있어.","JPN":"それに、構成員全員が動物的な超感覚を持っているから危険にも素早く対応できるしね。","ENG":"Also, everyone here has animal-like senses which we use to quickly respond to danger.","TWN":"此外，所有成員都擁有動物般的超感應，因此他們可以快速應對危險。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"일반적인 카운터보다 이면세계에서의 생존률이 훨씬 높지.","JPN":"一般的なカウンターよりは裏世界での生存率が遥かに高いよ。","ENG":"In other words, our survivability rate in the Counterside is higher than that of normal Counters.","TWN":"綜上而言，我們在異界的生存率比普通制裁者要高很多。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그럼에도…… 수색 작전은 결코 만만하지 않아.","JPN":"それでも……捜索作戦は、決して簡単なことじゃない。","ENG":"But even then... search operations aren't easy.","TWN":"即便如此……偵察作戰絕非易事。"},"stage":{"bg":"TRAINING","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L1_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"이면세계에서는 그 무엇도 장담할 수 없으니까.","JPN":"裏世界では何が起こるか、誰にもわからないからね。","ENG":"That's because nothing is guaranteed in the Counterside.","TWN":"因為在異界，沒有什麼是可以保證的。"},"stage":{"bg":"TRAINING","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"저는 반대입니다요.","JPN":"あたいは反対でやんす。","ENG":"I'm against it.","TWN":"我不同意。"},"stage":{"bg":"TRAINING","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"뭐야, 꼬맹이. 갑자기 정색을 하고.","JPN":"なんだよ、急に真顔になって。","ENG":"Kid? Why are you suddenly so serious?","TWN":"怎麼了，小鬼？突然一臉嚴肅的。"},"stage":{"bg":"TRAINING","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"아무것도 모르는 신참 녀석에게 다이브는 한참 무리라고 생각합니다요.","JPN":"なんにも知らない新入りに、ダイブはまだ早いと思うでやんす。","ENG":"I think it's a bad idea to let a clueless rookie dive into the Counterside.","TWN":"我覺得躍入對於一個什麼都不懂的新人來說，還是太勉強了。"},"stage":{"bg":"TRAINING","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"무엇보다도 첫 다이브에서는 그게 나오지 않습니까요.","JPN":"なにより、初ダイブではあれが出るじゃないでやんすか。","ENG":"And above all, that thing always appears on first dives.","TWN":"最重要的是，第一次躍入的時候不是會出現那個嗎？"},"stage":{"bg":"TRAINING","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"……<color=#ffd34c>그림자</color>가.","JPN":"……<color=#ffd34c>シャドウ</color>が。","ENG":"... A <color=#ffd34c>Shadow</color>.","TWN":"……<color=#ffd34c>暗影</color>。"},"stage":{"bg":"TRAINING","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그림자? 그림자라면, 그 카운터가 침식되어 발생한 상위종 침식체?","JPN":"シャドウ？　カウンターが侵食されて発生した、上異種の侵食体のことか？","ENG":"Shadow? You mean the high-category C.O. that emerges from when a Counter gets Corrupted?","TWN":"暗影？你說的是制裁者被侵蝕後而產生的高階侵蝕體？"},"stage":{"bg":"TRAINING","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"인간의 말을 할 수 있고, 지능이 있는 녀석들이라고 들었는데…….","JPN":"人語が喋れて、知能を持つやつらだと聞いているが……","ENG":"I heard they have intelligence and can even speak our language...","TWN":"聽說他們會說人類的語言，還很聰明……"},"stage":{"bg":"TRAINING","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"맞아. 도시 전설 같은 이야기로 들릴지 모르겠지만.","JPN":"そうよ。都市伝説みたいな話だけど。","ENG":"You're right. It may sound like some urban legend...","TWN":"沒錯。雖然這聽起來像是都市怪談……"},"stage":{"bg":"TRAINING","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>카운터가 이면세계에 처음으로 다이브하면, 거의 확정적으로 그림자가 따라붙거든.</color>","JPN":"<color=#ffd34c>初めて裏世界にダイブしたカウンターには、ほぼ確実にシャドウが付きまとうの。</color>","ENG":"But <color=#ffd34c>when a Counter dives into the Counterside for the first time, a Shadow will almost certainly appear.</color>","TWN":"但是<color=#ffd34c>制裁者第一次躍入異界時，百分百會伴隨出現暗影。</color>"},"stage":{"bg":"TRAINING","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"대부분은 <color=#ffd34c>데몬</color> 타입.","JPN":"そのほとんどは<color=#ffd34c>デーモン</color>タイプよ。","ENG":"Most of them are <color=#ffd34c>Demon</color>-types.","TWN":"大部分是<color=#ffd34c>惡魔</color>型。"},"stage":{"bg":"TRAINING","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"하지만 이면세계의 환경에 따라, <color=#ffd34c>도플갱어</color> 타입이 걸릴 수도 있지.","JPN":"でも裏世界の環境によって<color=#ffd34c>ドッペルゲンガー</color>タイプに遭遇する可能性もあるね。","ENG":"But depending on the environment of the Counterside, they could also be <color=#ffd34c>Doppelganger</color>-types.","TWN":"不過，根據異界的環境，也可能出現<color=#ffd34c>二重身</color>型。"},"stage":{"bg":"TRAINING","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"어쨌든 적어도 3종 이상이라고 생각하는 편이 좋을 거야.","JPN":"とにかく、第3種以上はほぼ確実に遭遇すると思っていたほうがいいよ。","ENG":"Anyway, it's better to think of them as at least a Category 3.","TWN":"總之，你就將它們當作是至少3類的侵蝕體。"},"stage":{"bg":"TRAINING","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TRAINING","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"다시 말해, 3종 침식체 정도는 격파할 수 있어야 다이브를 권장한다 이거야?","JPN":"つまり、第3種侵食体ぐらいは撃破できる能力がないと、ダイブは推奨できないってことか。","ENG":"In other words, you're recommending that I dive when I can handle a Category 3 C.O. on my own?","TWN":"也就是說，我要有至少能夠擊敗3類侵蝕體的實力才建議躍入，對吧？"},"stage":{"bg":"TRAINING","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"우리 야크샤 전대에서는 신참의 첫 다이브를 <color=#ffd34c>신고식</color>이라고 불러.","JPN":"私たちヤクシャー戦隊では、新入りの初ダイブを<color=#ffd34c>通過儀礼</color>と呼んでいるよ。","ENG":"In the Yaksha Division, a rookie's first dive is called a <color=#ffd34c>debut</color>.","TWN":"我們夜叉戰隊將新隊員第一次的躍入稱為<color=#ffd34c>出道</color>。"},"stage":{"bg":"TRAINING","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"자기에게 이끌린 그림자는 스스로 끊어내야 한다는 뜻이지.","JPN":"自分にとり憑いたシャドウは、自分で断ち切るしかないの。","ENG":"So, you'll have to defeat the Shadow attracted to you with your own hands in your debut.","TWN":"意思就是你要靠自己斬斷暗影。"},"stage":{"bg":"TRAINING","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"첫 다이브부터 무리해서 깊게 다이브하지는 않겠지만, 그래도 그림자와 맞붙게 될 거야.","JPN":"初回から無理して深くまでダイブさせることはないけど、間違いなくシャドウと対戦することになる。","ENG":"We won't dive too deep for your first time, but you will still fight a Shadow.","TWN":"雖然第一次不會躍入太深，但仍然會遇到暗影。"},"stage":{"bg":"TRAINING","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그러니 마음의 준비가 끝나면, 그때 말해줘도 괜찮아.","JPN":"だから心の準備ができたら、その時伝えて。","ENG":"So let me know when you're ready.","TWN":"所以，當你做好心理準備之後，就可以告訴我了。"},"stage":{"bg":"TRAINING","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TRAINING","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"아직은 이렇게 멀리서 지켜보는 게 전부겠지만.","JPN":"今はこうして遠くから眺めるだけだが。","ENG":"Even if observing from afar is all you can do right now,","TWN":"雖然，現在的你只能遠遠地看著。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L29_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"관리국에 계속 있을 생각이라면, 저 녀석의 뒷모습을 마음 속에 새겨둬라.","JPN":"管理局に居続けるつもりなら、あいつの背中を忘れるな。","ENG":"if you're thinking of staying in the Administration, take the image of her back to the heart.","TWN":"但如果你打算繼續留在管理局，就好好記住那傢伙的背影吧。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"저 모습은 언젠가 네가 다다라야 할 모습이고, 또 누군가에게 보여주게 될 모습이니까.","JPN":"あれはいつかお前が辿り着かねばならない境地であり、また誰かに見せてやらねばならない姿なのだから。","ENG":"That is what you'll have to become and show to others one day.","TWN":"那將會是你總有一天會達到的樣子，也是別人會看到你的樣子。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"난 소방관이야. 준비 같은 건 언제든 되어있어…….","JPN":"アタシは消防士だ。準備ならいつでもできてる……","ENG":"I'm a firefighter. I'm always ready...","TWN":"我是一名消防員。我隨時都準備好……"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L32_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그 왈가닥도 한 방에 4종을 날려버렸는데, 겨우 3종 가지고 머뭇거릴 이유는 없지.","JPN":"あのお転婆も一撃で第4種を蹴散らしたんだ。たかが第3種で戸惑うわけない。","ENG":"That tomboy defeated a Category 4 with one blow. So, there's no reason for me to be afraid of a Category 3.","TWN":"那個瘋丫頭一擊就打飛了4類侵蝕體，我沒理由去害怕一個3類侵蝕體。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그래서, 작전 준비는 언제부터 하면 되는데?","JPN":"で、作戦準備はいつからやればいいんだ？","ENG":"So? When do we start this operation?","TWN":"那麼，我應該什麼時候開始作戰呢？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};